10→const SETTINGS_STORAGE_KEY = 'settings-general';
11→
12→function isSettingsWithPosition(v: unknown): v is { windowPosition: string } {
13→  return (
14→    typeof v === 'object' &&
15→    v !== null &&
16→    'windowPosition' in v &&
17→    typeof v.windowPosition === 'string'
18→  );
19→}
