21→const clipboard: PlatformClipboard = {
22→  async writeText(text: string) {
23→    const { writeText } = await import('@tauri-apps/plugin-clipboard-manager');
24→    await writeText(text);
25→  },
26→  async readText() {
27→    const { readText } = await import('@tauri-apps/plugin-clipboard-manager');
28→    return readText();
29→  },
30→  async onClipboardChange(handler: (event: ClipboardChangeEvent) => void) {
31→    const { listen } = await import('@tauri-apps/api/event');
32→    return listen<ClipboardChangeEvent>('clipboard-changed', event => {
33→      handler(event.payload);
34→    });
35→  },
36→};
37→
38→const shell: PlatformShell = {
39→  async openUrl(url: string) {
40→    try {
41→      const parsed = new URL(url);
42→      if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
43→        return;
44→      }
45→    } catch {
46→      return;
47→    }
48→    window.open(url, '_blank', 'noopener,noreferrer');
49→  },
50→  async openDeepLink(url: string) {
51→    const anchor = document.createElement('a');
52→    anchor.href = url;
53→    anchor.click();
54→  },
55→};
